TRANSLATIONS: dict[int, dict] = {
201: {"nativeDefinition": "Small assorted items or parts; also used for trying a little of everything or reading only portions of something.", "japaneseMeaning": "あれこれ、断片的に", "etymology": "bit（小片）と piece（部分）を並べたイディオムで、さまざまな小さなものや部分的な内容を表す。", "examples": {"B": "色々試したいからお弁当にしよう。", "C": "記事が退屈で長かったので、断片的にしか読まなかった。", "D": "いろいろな種類の小さなもの、細かい部分"}},
202: {"nativeDefinition": "A positive aspect or benefit found within an otherwise bad situation.", "japaneseMeaning": "不幸中の幸い、良い面", "etymology": "「暗い雲の銀色の縁」という比喩から、悪い事柄の中にある希望や良い側面を指す。", "examples": {"B": "足を骨折した不幸中の幸いは、来週1週間仕事に行かなくていいことだ。", "C": "大恐慌にも良い面があった。その間、食生活の変化で米国の平均寿命は伸びた。", "D": "前向きな側面"}},
203: {"nativeDefinition": "To take someone's words or criticism seriously and be emotionally affected by them.", "japaneseMeaning": "（何かを）真剣に受け止める、心に刻む", "etymology": "heart（心）に取り込むという表現で、言葉を深く心に留めることを表す。", "examples": {"B": "マットは今日イライラしているから、彼のコメントをあまり心に留めない方がいい。", "C": "レイはエリックのフィードバックを真剣に受け止めたようで、かなり落ち込んでいる。", "D": "何かを真剣にとらえる"}},
204: {"nativeDefinition": "To temporarily set aside a topic, task, or issue to deal with later.", "japaneseMeaning": "（何かを）一旦保留にする、脇に置く", "etymology": "車を駐車場に停める park から転じ、問題や議題を一時的に横に置く比喩。", "examples": {"B": "この質問、今は一旦保留にできる？今ほかの問題を片付けようとしているんだ。", "C": "今日中にこの記事を仕上げる必要はないから、一旦脇に置いて先にこっちを進めよう。", "D": "何かを後回しにする"}},
205: {"nativeDefinition": "By any means necessary, using whatever method works—even questionable ones.", "japaneseMeaning": "手段を選ばず、何としてでも", "etymology": "hook（フック）と crook（曲がった杖）という略奪の道具から、正邪を問わず達成する意。", "examples": {"B": "金曜までに何としても本の執筆を終わらせる。", "C": "アダムは手段を選ばず、いつも期限内にタイムシートを提出している。", "D": "どんな手段を使ってでも"}},
206: {"nativeDefinition": "A quick review to verify that something is reasonable, logical, or roughly correct.", "japaneseMeaning": "妥当性チェック、概ね正しいか確認すること", "etymology": "sense（常識・理路）を check（確認する）した合成語。ビジネスで広く使われる。", "examples": {"B": "会社の業績について妥当性チェックをしよう。直近の売上を過去の推移と比べてみて。", "C": "計算がおおむね正しいか、妥当性チェックをしてもらえる？", "D": "見直し"}},
207: {"nativeDefinition": "Completely unable to answer, figure out, or respond to something.", "japaneseMeaning": "困り果てた、答えられない", "etymology": "木桩に足をぶつけて動けなくなるイメージ、または演壇の stump から弁論する場面に由来する説もある。", "examples": {"B": "あの数学の問題に本当に困った。", "C": "ジョンはロビンの予想外の質問に答えに窮した。", "D": "混乱した"}},
208: {"nativeDefinition": "To return to a previous topic in a discussion, or to follow up with someone later.", "japaneseMeaning": "（話題・誰かに）後で戻る、改めて取り上げる", "etymology": "circle（輪を描く）back（戻る）で、議論の流れが一旦離れてから元の点に戻る比喩。", "examples": {"B": "さっきヘンリーが言った点に戻してもらえる？", "C": "チャールズと話してから、あなたの質問に改めて答えるね。", "D": "何か・誰かのところに戻る"}},
209: {"nativeDefinition": "A person (often a boss) who demands a lot and is strict about performance.", "japaneseMeaning": "手の厳しい上司、容赦ない監督者", "etymology": "taskmaster（作業を監督する者）に hard（厳しい）を付けた表現。", "examples": {"B": "グレンの上司は手の厳しい人だ。", "C": "彼女の下で働くのは嫌だ。本当に容赦ない監督者なんだ。", "D": "過度に要求の厳しい人"}},
210: {"nativeDefinition": "Completely different; used to contrast two things that are polar opposites.", "japaneseMeaning": "昼夜ほど違う、まったく異なる", "etymology": "昼と夜という対極の時間帯から、正反対であることを表す。", "examples": {"B": "ケリーは仕事中と仕事後では人柄がまったく違う。", "C": "兄と僕は昼夜ほど違う。", "D": "まったく異なる"}},
211: {"nativeDefinition": "To disappoint someone by revealing an unpleasant truth that ruins their optimism.", "japaneseMeaning": "（誰かの）楽しい空想を打ち砕く、余計なことを言う", "etymology": "泡（bubble）を割るように、楽観的な幻想を突然壊す比喩。", "examples": {"B": "余計なこと言うのは嫌なんだけど、次の昇給は思っていたほど大幅じゃないよ。", "C": "ぶっつけ本番で言うのも忍びないんだけど、彼のインスタ自撮りに誰も興味ないって誰か伝えないと。", "D": "人の前向きな見方を一瞬で変える"}},
212: {"nativeDefinition": "To damage someone's reputation through public criticism or negative talk.", "japaneseMeaning": "（誰かの）名前を汚す、名誉を傷つける", "etymology": "泥（mud）の中で名前を引きずる比喩で、評判を地に落とすことを表す。", "examples": {"B": "会議中、フランクの名前をひどく汚した。", "C": "チーム全体の失敗だったのに、誰かの名前をわざわざ汚す必要はない。", "D": "人の評判を損なう"}},
213: {"nativeDefinition": "A thorough, detailed investigation or analysis of a topic.", "japaneseMeaning": "徹底的な調査、深掘り", "etymology": "dive（潜る）の比喩で、表面ではなく深部まで掘り下げること。", "examples": {"B": "デザイン部門がここ2年で大量退職している理由を深掘りすべきだ。", "C": "マットがエレキの電気代を徹底的に調査して、異常に高い原因を突き止めた。", "D": "詳細な分析"}},
214: {"nativeDefinition": "The essence of something can be reduced to one key factor or conclusion.", "japaneseMeaning": "要するに何かだ、〜に尽きる", "etymology": "煮詰めて（boil down）最後に残るものから、本質が何かだと表現。", "examples": {"B": "このプロジェクトの成功は、コスト管理がうまくできるかに尽きる。", "C": "我々の弱い勝率は、得点が足りないことに帰着する。", "D": "要約すると何かになる"}},
215: {"nativeDefinition": "To start something immediately at full speed and productivity.", "japaneseMeaning": "最初から全力で取り組む、すぐに成果を出す", "etymology": "着地と同時に走り出す軍事用語から転じ、準備万端で始める意。", "examples": {"B": "講義前にノートを読んでおくと、講義に入ったらすぐ本腰を入れられる。", "C": "パットは前夜の準備のおかげで、初日から成果を出せた。", "D": "好調にスタートする"}},
216: {"nativeDefinition": "In a bad mood for no clear reason since waking up.", "japaneseMeaning": "機嫌が悪い、調子が悪い", "etymology": "縁起でもない方から起きたという古い迷信に由来するイディオム。", "examples": {"B": "ティニー、今朝はどうも機嫌が悪いみたいだね。", "C": "さっきは失礼だった。今朝はどうも調子が悪くて。", "D": "不機嫌であること"}},
217: {"nativeDefinition": "Easy targets that can be achieved with minimal effort.", "japaneseMeaning": "容易に手に入る成果、格好の標的", "etymology": "低い位置にある実（low-hanging fruit）の比喩で、少ない労力で得られるもの。", "examples": {"B": "このプラットフォーム上の大多数のサイトは、ハッカーにとって格好の標的だと何年も見なされてきた。", "C": "暗号資産投資で儲けるのは難しくなってきた。容易に手に入る果実はもうほとんど摘み取られている。", "D": "簡単に達成できる目標"}},
218: {"nativeDefinition": "An activity that helps strangers feel comfortable and relaxed together.", "japaneseMeaning": "場を和ませるきっかけ、緊張をほぐす活動", "etymology": "氷（ice）を割る（break）ように、初対面の人間関係のぎこちなさを解く比喩。", "examples": {"B": "チームでランチに行くのは、場を和ませるのにいい方法だ。", "C": "参加者がリラックスできるよう、場慣れゲームを企画しよう。", "D": "互いに知らない人たちが一緒にリラックスできる活動"}},
219: {"nativeDefinition": "To create a rough draft or prototype to show what something will look like.", "japaneseMeaning": "（何かの）試作を作る、ラフを描く", "etymology": "mock（模造）と up（完成形に近づける）の句動詞で、本番前の試作を表す。", "examples": {"B": "ライアンがプレゼンの試作版を作って、見た目を見せてくれる。", "C": "間取りの図をいくつかラフで描いてもらえる？", "D": "何かの下書きを作る"}},
220: {"nativeDefinition": "Approximately; used after numbers or times in casual speech.", "japaneseMeaning": "ほど、くらい", "etymology": "so（その程度）と組み合わせ、おおよその量や時刻を表す口語表現。", "examples": {"B": "彼は30歳くらいだと思う。", "C": "5時ごろに会えない？", "D": "おおよそ"}},
221: {"nativeDefinition": "A person competent at many skills but not necessarily an expert in one.", "japaneseMeaning": "何でも屋、幅広い能力を持つ人", "etymology": "あらゆる職業のジャック（男）という17世紀の表現。後半 master of none が省略されることも。", "examples": {"B": "アレックスは好みのポジションは特になく、何でも屋タイプだ。", "C": "彼は何でも屋として知られている。会計士からサッカーコーチ、コメディアンまで経験している。", "D": "多方面に通じた人"}},
222: {"nativeDefinition": "Plain, boring, ordinary, and unexciting.", "japaneseMeaning": "退屈な、ごく普通の", "etymology": "最も基本的なバニラ味が地味な代表として、普通で刺激のないものを比喩する。", "examples": {"B": "天気はとても退屈な会話の話題だ。", "C": "マイクはごく普通の人だ。", "D": "地味で平凡"}},
223: {"nativeDefinition": "Stubborn and unwilling to change one's mind.", "japaneseMeaning": "頑固な、強情な", "etymology": "hard（硬い）＋ headed（頭）で、考えが固く曲げない様子を表す。", "examples": {"B": "リディアは時々とても頑固だ。", "C": "エイミーとは付き合いにくい。とても強情だから。", "D": "頑固"}},
224: {"nativeDefinition": "To argue an opposing view to stimulate debate, not necessarily because you believe it.", "japaneseMeaning": "あえて反対意見を述べる、悪魔の代弁者を務める", "etymology": "カトリック教会で悪魔の立場を代弁する役割から転じ、議論を深めるための反対意見を表す。", "examples": {"B": "資金調達の最短ルートはデイヴィッドに頼むことだよね？悪魔の代弁をすると、もっと信頼できる人はいる？", "C": "頭がいいのは良いことだと言うけど、あえて反対意見を言うと、賢いのは良くて愚かなのは悪いと、なぜ言えるの？", "D": "議論のために反対・代替の見方を取る"}},
225: {"nativeDefinition": "To make a plan or idea clear, definite, and fully formed.", "japaneseMeaning": "（計画・考えを）明確にする、固める", "etymology": "crystal（結晶）のように曖昧なものをはっきり形にする比喩。", "examples": {"B": "ディズニーランドに行くなら、常に混んでいるからどのアトラクションに行くか作戦を固めるべきだ。", "C": "最終的な建物の姿をはっきりさせるには、設計が現実的かどうかエンジニアの意見が必要だ。", "D": "何かを最終決定する"}},
226: {"nativeDefinition": "A deep, serious, personal conversation about meaningful topics.", "japaneseMeaning": "深い話、本音で語り合う会話", "etymology": "Deep and Meaningful の頭文字 D&M から来る俗語。", "examples": {"B": "ジャックは二人の今後の進み方について、深い話をした。", "C": "昨日マークと彼の新しい彼女について、じっくり語り合った。", "D": "深く意味のある会話"}},
227: {"nativeDefinition": "A sociable person who enjoys and is skilled at interacting with others.", "japaneseMeaning": "人付き合いがうまい人、社交的な人", "etymology": "people（人々）＋ person（人）の重ねで、人と関わるのが得意な人を表す。", "examples": {"B": "ジリアンは本当に人付き合いがうまく、誰とでも会話を始められる。", "C": "オリバーは間違いなく社交的な人だ。今日初めて会った同僚と何時間も話している。", "D": "社交的な人"}},
228: {"nativeDefinition": "To finish or complete something, especially under deadline pressure.", "japaneseMeaning": "何とか仕上げる、ゴールに到達させる", "etymology": "ゴールライン（line）を越えるスポーツの比喩から、仕事を完了させる意。", "examples": {"B": "この仕事を何とか今日中に終わらせて、早く帰ろう。", "C": "ずっと促さないと、タルムは課題を期限までに仕上げない。", "D": "何かを完了する"}},
229: {"nativeDefinition": "To expand into new areas, markets, or fields.", "japaneseMeaning": "事業・活動の幅を広げる", "etymology": "木の枝（branch）が広がるように、活動範囲を拡大することを表す。", "examples": {"B": "そのシネマソフト会社は、VRなど他の市場にも進出し始めた。", "C": "経理以外の経験を積むために、他の部署にも手を広げている。", "D": "拡大する"}},
230: {"nativeDefinition": "Using your own money that may not be reimbursed.", "japaneseMeaning": "自腹を切る、立て替える", "etymology": "pocket（懐）から out（出す）で、自分の金を出すことを表す。", "examples": {"B": "保険証があれば、診察のとき自腹で払う必要はない。", "C": "会社がタクシー代を払ってくれないので、50ドル自腹を切った。", "D": "自分のお金を使う"}},
231: {"nativeDefinition": "To carefully refine and polish the wording of a text.", "japaneseMeaning": "（何かの）文章を練る、言葉を推敲する", "etymology": "wordsmith（言葉の職人）を動詞化し、言葉を巧みに磨く意。", "examples": {"B": "送る前にこの回答の文章を少し練る必要がある。", "C": "明日このブログ記事の言葉を磨けば、公開できる。", "D": "何かの表現を推敲する"}},
232: {"nativeDefinition": "Diluted, weakened, or made less intense or authentic.", "japaneseMeaning": "薄められた、色あせた", "etymology": "水で薄める（water down）の過去分詞形。内容や性質を弱める比喩。", "examples": {"B": "iPhoneのOSは、Mac OS Xの薄めた版のようなものだ。", "C": "Twitterが本当の私で、Facebookは色あせた版の私だと思う。", "D": "薄められた"}},
233: {"nativeDefinition": "To try to get compliments indirectly, often through hints or self-deprecation.", "japaneseMeaning": "お世辞を引き出す、褒め言葉を欲しがる", "etymology": "compliment（褒め言葉）を fish（釣る）ように、直接言わずに引き出す比喩。", "examples": {"B": "自分の写真をたくさん上げるのって、お世辞を欲しがってるんでしょ？", "C": "褒め言葉を求めるのは人をイラ立たせることもあるが、自信をつけるには意外と有効だ。", "D": "婉曲にお世辞を求める"}},
234: {"nativeDefinition": "To compromise by each side giving something up.", "japaneseMeaning": "（誰かと）互いに譲り合う、折衷する", "etymology": "中途（halfway）まで会い合うように、双方が譲歩することを表す。", "examples": {"B": "折衷してくれれば、二人とも満足できる結果になりそうだ。", "C": "チャメスとキャンは、提案の多くの点で意見が食い違っていて、折衷するのに苦労している。", "D": "誰かと妥協する"}},
235: {"nativeDefinition": "To remove undesirable items or people from a group through screening.", "japaneseMeaning": "（何かを）ふるいにかけて除去する、間引く", "etymology": "weed（雑草）を除く（out）という字面通りの比喩。", "examples": {"B": "履歴書選考の目的は、基本的に不適格な候補をふるい落とすことだ。", "C": "政府は日本に渡航する潜在的なテロリストを排除しようとしている。", "D": "何か・誰かを隔離して取り除く"}},
236: {"nativeDefinition": "One's spouse or romantic partner, used affectionately or humorously.", "japaneseMeaning": "伴侶、配偶者", "etymology": "自分より良い半分（better half）という愛称で、配偶者を指す。", "examples": {"B": "私の伴侶のサムを紹介してもいい？", "C": "彼女は伴侶が車を回してくるのを待っているところだ。", "D": "配偶者・パートナー"}},
237: {"nativeDefinition": "To temporarily stop an activity or discussion.", "japaneseMeaning": "一旦ストップする、中断する", "etymology": "再生ボタンの pause（一時停止）を押す比喩で、作業や議論を止める意。", "examples": {"B": "勉強しすぎて疲れたら、一旦ストップして少し休もう。", "C": "この議論は一旦中断しよう。続ける前にもう少し情報を集める必要がある。", "D": "一時停止する"}},
238: {"nativeDefinition": "To gradually slow down, reduce activity, or relax.", "japaneseMeaning": "落ち着く、段階的に終わりに近づく", "etymology": "時計のゼンマイが wind down（巻き終わる）ように、活動が徐々に止まる比喩。", "examples": {"B": "家の建設も落ち着いてきたので、来週からは工事の音がずっと少なくなるはずだ。", "C": "来週は仕事を休んで、少し心身を休めたい。", "D": "徐々に落ち着く"}},
239: {"nativeDefinition": "To make a large profit, often quickly or unexpectedly.", "japaneseMeaning": "大儲けする、暴利を上げる", "etymology": "killing（殺害）から転じ、莫大な利益を「刈り取る」イメージ。", "examples": {"B": "テレサはウサギショーの南カロライナ部門で大儲けしている。", "C": "スーは先月始めた副業で大儲けしている。", "D": "たくさんのお金を稼ぐ"}},
240: {"nativeDefinition": "To guess without knowing, when you have little or no information.", "japaneseMeaning": "当てずっぽうで答える、推測する", "etymology": "暗闇の中で刺す（stab in the dark）ように、見当もつかない推測を表す。", "examples": {"B": "答えがわからなかったので、当てずっぽうで答えた。", "C": "答えがわからなければ、当てずっぽうで言った方が何も言わないよりマシだよ。", "D": "完全に推測する"}},
241: {"nativeDefinition": "To view something with skepticism rather than accepting it fully.", "japaneseMeaning": "（何かを）話半分に聞く、鵜呑みにしない", "etymology": "一撮りの塩（grain of salt）と一緒に取るというラテン語に由来する表現。", "examples": {"B": "ジェフは片手で車を持ち上げられると言っていたけど、話半分に聞いた。", "C": "ジョンはトレントの話を鵜呑みにしなかった。正しそうに聞こえなかったから。", "D": "懐疑的に見る"}},
242: {"nativeDefinition": "An unofficial but widely followed custom or rule.", "japaneseMeaning": "暗黙のルール、不文律", "etymology": "unwritten（書かれていない）＋ rule（規則）で、文書化されていない慣習を表す。", "examples": {"B": "電車では、空席が他にもあるなら隣の席を取らないという暗黙のルールがある。", "C": "日本では、部屋に入るとき靴を脱ぐという不文律がある。", "D": "誰もが守るが書面にはない慣習"}},
243: {"nativeDefinition": "Not making progress; staying in the same place despite effort.", "japaneseMeaning": "足踏み状態、停滞している", "etymology": "水の中で足を動かして浮かぶが前に進まない泳ぎから転じた比喩。", "examples": {"B": "日本経済は20年以上足踏み状態だ。", "C": "ネビルは次のステップがわからず、足踏みしている。", "D": "進んでいない"}},
244: {"nativeDefinition": "Routine, tedious, low-level work that requires little skill.", "japaneseMeaning": "雑用、単調な下請け仕事", "etymology": "grunt（唸る）から、肉体的・単調で報われない作業を指す俗語。", "examples": {"B": "他にも仕事があるから、このプロジェクトの雑用は下のグレードの人に任せたい。", "C": "雑用を他の人に回してもらえない？もっと複雑な仕事で手伝ってほしいんだ。", "D": "単調な仕事"}},
245: {"nativeDefinition": "To be secretive about one's plans, intentions, or thoughts.", "japaneseMeaning": "手の内を明かさない、秘密主義", "etymology": "カードゲームで手札を胸に近づけて隠す動作からの比喩。", "examples": {"B": "キムは手の内を明かさないから、何を考えているかわからない。", "C": "次に誰が昇進するか皆気になっているが、上司は手の内を明かしていない。", "D": "秘密主義である"}},
246: {"nativeDefinition": "Unprecedented; never known to have happened before.", "japaneseMeaning": "前例のない、ありえない", "etymology": "un-（ない）＋ heard of（聞いたことがある）で、聞いたこともない異例を表す。", "examples": {"B": "ピンクのトラは前例がない。", "C": "1年で100本のホームランを打つなんて前代未聞だ。", "D": "前例のない"}},
247: {"nativeDefinition": "To enter oneself as a candidate or applicant for something.", "japaneseMeaning": "立候補する、応募する", "etymology": "帽子（hat）の中に名前を入れて抽選するという慣習から。", "examples": {"B": "君は候補としてぴったりだから、応募した方がいいよ。", "C": "面白そうな機会だから、自分の名前を出してみる。", "D": "人を支配する"}},
248: {"nativeDefinition": "Too good, advanced, or expensive for someone to attain.", "japaneseMeaning": "（誰かには）高嶺の花、手が届かない", "etymology": "スポーツのリーグ（級）から、自分の能力や地位の範囲外を表す。", "examples": {"B": "あの子に惚れているんだけど、自分には高嶺の花だ。", "C": "あの一眼レフカメラは、僕の手が届かない値段だ。", "D": "誰かには高すぎる・良すぎる"}},
249: {"nativeDefinition": "To recall or reflect on a past event or time.", "japaneseMeaning": "（何かを）振り返る、思い出す", "etymology": "think（考える）＋ back（過去へ）で、過去の出来事を思い起こす意。", "examples": {"B": "彼女は経済学の試験に遅刻したときのことを思い出した。", "C": "先週の会議を振り返れば、この件はもう話し合ったはずだ。", "D": "何かを思い出す"}},
250: {"nativeDefinition": "To abandon someone without support or resources when they need help.", "japaneseMeaning": "（誰かを）見捨てる、置き去りにする", "etymology": "高潮時に船が引き潮で干上がった砂州に置き去りにされるイメージから。", "examples": {"B": "首相は、ホームレスの人々を見捨てないと述べた。", "C": "お客への謝罪は僕も一緒に行くよ。一人ぼっちで放り出しはしたくないから。", "D": "誰かを助けずに置き去りにする"}},
251: {"nativeDefinition": "A fortunate chance event that helps you succeed or get ahead.", "japaneseMeaning": "幸運なチャンス、思わぬ好都合", "etymology": "lucky（幸運な）＋ break（チャンス）で、思いがけない好機を表す。", "examples": {"B": "成功するキャリアには、所々で幸運なチャンスが必要だ。", "C": "レストランでラッキーな好都合があった。直前にキャンセルが出て、席を取れたんだ。", "D": "幸運な出来事"}},
252: {"nativeDefinition": "To try as hard as possible and make the best impression.", "japaneseMeaning": "最善を尽くす、全力を出す", "etymology": "最善の足（best foot）を前に出すという古い表現から、全力を出す意。", "examples": {"B": "ガブリエルは面接で最善を尽くした。", "C": "最善を尽くさなければ、試合に勝てないよ。", "D": "最善を尽くす"}},
253: {"nativeDefinition": "To have ultimate authority to make the final decision.", "japaneseMeaning": "最終決定権を持つ", "etymology": "final（最終の）＋ say（発言権）で、最後の判断を下す権限を表す。", "examples": {"B": "上司は重要な決定の前に必ず相談してくれるが、結局最終決定権は彼にある。", "C": "自分の未来を決めるのは、本人が最終決定権を持つべきだと思う。", "D": "最終決定する権力を持つ"}},
254: {"nativeDefinition": "To fail or mess up an important opportunity.", "japaneseMeaning": "大事な場面で失敗する、チャンスを棒に振る", "etymology": "blow（吹き飛ばす）it（それ）で、せっかくの機会を台無いにする口語表現。", "examples": {"B": "うちのチーム、昨夜本当に大失敗した。ハーフタイムで大差をつけていたのに負けた。", "C": "エミリーは就職面接で本当に台無しにした。", "D": "チャンスを逃す"}},
255: {"nativeDefinition": "To fit perfectly in size or placement.", "japaneseMeaning": "ぴったり合う", "etymology": "手袋（glove）のようにぴったりフィットする比喩。", "examples": {"B": "この新しいジャケット、ぴったり合う。", "C": "食洗機はキッチンの隅にぴったり収まった。", "D": "完璧に合う"}},
256: {"nativeDefinition": "To stop while you're winning to avoid losing your gains.", "japaneseMeaning": "（誰かが）勝っているうちに止める", "etymology": "有利なうちに（while ahead）やめることで、得たものを失わない知恵を表す。", "examples": {"B": "トムはカジノで100ドル勝ち越していたので、そのうちに止めた。", "C": "会社を売却に出そう。調子が良いうちに止めるのが大事だ。", "D": "有利なうちにやめる"}},
257: {"nativeDefinition": "To reverse a bad situation and make it positive again.", "japaneseMeaning": "状況を好転させる、立て直す", "etymology": "turn（回す）it（それ）around（逆方向に）で、状況を180度変える意。", "examples": {"B": "会社にはいくつか問題があったが、新CEOが何とか立て直した。", "C": "自信を失っているが、最善を尽くして立て直すつもりだ。", "D": "マイナス状況を逆転させる"}},
258: {"nativeDefinition": "To reveal one's plans, intentions, or strategy too early.", "japaneseMeaning": "手の内を明かす、本音を見せる", "etymology": "カードゲームで手札（hand）を見せる比喩。交渉で戦略を明かすことを表す。", "examples": {"B": "ビジネス交渉では、すぐに手の内を明かしてはいけない。", "C": "新製品の発表は今は控えよう。競合に早く手の内を見せるのは賢くない。", "D": "計画・意図・考えを明かす"}},
259: {"nativeDefinition": "Approximately; used with dates or numbers, especially in formal writing.", "japaneseMeaning": "約、およそ（年代・数値）", "etymology": "ラテン語 circa（約）から。年代や数量の概数を示す。", "examples": {"B": "マクドナルドは1960年頃に設立された。", "C": "昨年の利益は約200万ドルだった。", "D": "おおよそ"}},
260: {"nativeDefinition": "To make something more exciting, attractive, or lively.", "japaneseMeaning": "（何かを）華やかにする、にぎやかにする", "etymology": "ジャズ音楽の活気から、物事を派手に活気づける比喩。", "examples": {"B": "壁をライトグリーンに塗って、家を華やかにするつもりだ。", "C": "ブレットはLEDライトを付けて車を派手にした。", "D": "何かをもっと楽しく魅力的にする"}},
261: {"nativeDefinition": "To be very noticeable in a bad or awkward way.", "japaneseMeaning": "目立ちすぎる、場違いに目立つ", "etymology": "痛い親指（sore thumb）のように目立ってしまう比喩。", "examples": {"B": "明るい色の車に汚れがあると、すごく目立つ。", "C": "正装の場で明るいスーツを着たので、マットは場違いに目立っていた。", "D": "悪い意味で非常に目立つ"}},
262: {"nativeDefinition": "Born into wealth and privilege, never needing to struggle financially.", "japaneseMeaning": "恵まれた環境で生まれた、金持ちの生まれ", "etymology": "銀のスプーンを口にくわえて生まれるという貴族の象徴から。", "examples": {"B": "ウィルは裕福な家庭の生まれなので、あまり働く必要がない。", "C": "トレントは挫折に弱く、恵まれた環境で育った人のようだ。", "D": "裕福な家庭に生まれた"}},
263: {"nativeDefinition": "Uncertain; the outcome is not yet determined.", "japaneseMeaning": "どうなるかわからない、危うい", "etymology": "触れたら崩れそう（touch and go）という危険な状態から転じた。", "examples": {"B": "その夜ほかの予定もあるので、パーティーに行けるかは微妙だ。", "C": "資金が確保できるまで、プロジェクトは危うい状態だ。", "D": "不確実"}},
264: {"nativeDefinition": "To leave a place (casual slang).", "japaneseMeaning": "退散する、さっと出る", "etymology": "跳ね返る（bounce）から、さっと立ち去る若者言葉として使われる。", "examples": {"B": "遅くなってきたから、退散しよう。", "C": "ここ退屈だね。さっと出よう。", "D": "去る"}},
265: {"nativeDefinition": "Working and operational again after setup or repairs.", "japaneseMeaning": "稼働している、正常に動いている", "etymology": "up（起動して）and running（走っている）で、機械やシステムが正常稼働する意。", "examples": {"B": "今朝は車を動かすのに数時間かかった。", "C": "数週間の修理を経て、ついに飛行機が再稼働した。", "D": "稼働中"}},
266: {"nativeDefinition": "Private, embarrassing personal matters one prefers not to reveal.", "japaneseMeaning": "家の事情、恥ずかしい内緯", "etymology": "洗濯物の比喩で、人前にさらしたくない私的問題を指す。", "examples": {"B": "父が実は元プロ選手だなんて言わなかった。家の内緯を公にしたくなかったから。", "C": "その政治家は汚い過去を隠している。", "D": "非常に私的で個人的な問題"}},
267: {"nativeDefinition": "To cause trouble or disrupt a stable situation unnecessarily.", "japaneseMeaning": "波風を立てる、穏やかな状態を乱す", "etymology": "船を揺らす（rock the boat）と転覆するイメージから、平和を乱す意。", "examples": {"B": "波風を立てたいわけじゃないんだけど、うちのアプローチは間違ってると思う。", "C": "一度に人を雇いすぎると、不必要に波風が立ちそうだ。", "D": "混乱を招く"}},
268: {"nativeDefinition": "To give permission or approval to proceed with something.", "japaneseMeaning": "許可を出す、スタートを認める", "etymology": "交通信号の緑色から、進行許可を表す比喩。", "examples": {"B": "ミシェルが許可を出したので、プロジェクトの調査フェーズを始めた。", "C": "クライアントが待ちくたびれているので、建設開始の許可を出すべきだ。", "D": "許可を与える"}},
269: {"nativeDefinition": "Fixed and cannot be changed.", "japaneseMeaning": "確定している、変更できない", "etymology": "石（stone）に刻むように、変更不能な状態を表す。", "examples": {"B": "ゲストが航空券を取っていてデポジットも払っているので、結婚式の日は確定だ。", "C": "留学2日目の日程はまだ何も予約していないので、変更可能だ。", "D": "もはや変更できない"}},
270: {"nativeDefinition": "A compliment that also insults or has a negative undertone.", "japaneseMeaning": "皮肉混じりの褒め言葉、毒入りの褒め言葉", "etymology": "backhanded（裏打ちの）compliment（褒め言葉）で、表面は褒めて中身は批判する意。", "examples": {"B": "あの女性、「その髪型好き。刈りたての芝みたい」って言ってたよ。これって毒入りの褒め言葉でしょ？", "C": "キャシーが彼女に「小柄な子って太もも丈のブーツ履けないと思ってたけど、君は似合ってる」って。完全に皮肉混じりの褒め言葉だ。", "D": "褒め言葉だが否定的な含意もある"}},
271: {"nativeDefinition": "To speak about someone very positively and enthusiastically.", "japaneseMeaning": "（誰かを）褒めちぎる、大絶賛する", "etymology": "sing（歌う）praise（賛美）で、人の良さを熱心に語る意。", "examples": {"B": "ジョンは君と一緒に働くのが本当に好きみたい。彼女のことを褒めちぎってるよ。", "C": "採用担当に君のことを大絶賛してるから、仕事は比較的楽に取れるはずだ。", "D": "誰かを熱心に褒める"}},
272: {"nativeDefinition": "To give credit or recognition to someone (informal slang).", "japaneseMeaning": "（誰かに）敬意を、感謝を", "etymology": "proper respect（当然の敬意）の略 props から来るスラング。", "examples": {"B": "結婚式の準備を手伝ってくれたダニーに感謝。", "C": "ITのトラブルを助けてくれたジェイミーに敬意を。", "D": "誰かに名誉を与える"}},
273: {"nativeDefinition": "Starting fresh without influence from past history or events.", "japaneseMeaning": "白紙の状態で、過去のしがらみなく", "etymology": "消した黒板（slate）の比喩で、過去の記録なく新たに始める意。", "examples": {"B": "海外に移住すれば、キャリアを白紙の状態から始められる。", "C": "このプレゼンは白紙から作り直そう。", "D": "過去の影響を受けない状態で"}},
274: {"nativeDefinition": "An angry, resentful attitude from feeling wronged or needing to prove oneself.", "japaneseMeaning": "負け惜しみ、心に刺さった恨み", "etymology": "肩（shoulder）に屑（chip）を乗せたという古い習慣に由来するという説がある。", "examples": {"B": "ジェームズはトップ5に入れなかった反動で、負け惜しみを抱えている。", "C": "マイケルは常に負けず嫌いなプレイヤーだ。", "D": "怒りや不快感を持った態度"}},
275: {"nativeDefinition": "Hurry up (informal, sometimes playful).", "japaneseMeaning": "急いで、さっさと", "etymology": "中国語の混じった英語（pidgin）起源とされる催促の言葉。", "examples": {"B": "さっさと。1時間後に飛行機だよ。", "C": "さあ、急いで、遅れるよ。", "D": "急げ"}},
276: {"nativeDefinition": "Very calm and composed under pressure.", "japaneseMeaning": "冷静沈着、動じない", "etymology": "冷たいきゅうり（cucumber）のように落ち着いているという比喩。", "examples": {"B": "一日中お客から厳しい質問を浴びせられていたが、ライアンは冷静だった。", "C": "その選手は大きなプレッシャーの下でも動じなかった。", "D": "とても落ち着いている"}},
277: {"nativeDefinition": "To start working seriously and with focus.", "japaneseMeaning": "本気で取り組む、腰を据える", "etymology": "ナックル（指関節）をついて真剣に取り組む姿勢から。", "examples": {"B": "イアンは腰を据えて試験勉強を始めた。", "C": "本気出して、このプロジェクトを何とか仕上げよう。", "D": "真剣になる"}},
278: {"nativeDefinition": "A key lesson or point to remember from a meeting or training.", "japaneseMeaning": "要点、学び", "etymology": "take away（持ち帰る）の名詞形で、会議などから得た重要な点を表す。", "examples": {"B": "この研修から得た3つの要点を共有してもらえる？", "C": "会議の主な学びは、市場がどれだけ競争激化しているかという点だった。", "D": "重要なポイント"}},
279: {"nativeDefinition": "A brief summary of what was covered previously.", "japaneseMeaning": "おさらい、要約", "etymology": "recapitulate（要約する）の略 recap で、内容を簡潔に振り返る意。", "examples": {"B": "始める前に、先週扱った内容を簡単におさらいする。", "C": "シーズン2の前に、シーズン1で何が起きたかを簡単に振り返ろう。", "D": "要約"}},
280: {"nativeDefinition": "To sound familiar; to trigger a vague memory.", "japaneseMeaning": "心当たりがある、思い出せそう", "etymology": "ベルの音が聞こえる（ring）ように、記憶のどこかで反応する比喩。", "examples": {"B": "クリス・リーという名前は心当たりがないかもしれないが、彼女は中国でとても有名な歌手だ。", "C": "その曲、どこかで聞いた気がするけど、曲名は思い出せない。", "D": "なんとなく聞き覚えがある"}},
281: {"nativeDefinition": "To speak plainly and honestly without euphemism.", "japaneseMeaning": "ありのまま言う、率直に言う", "etymology": "スコップをスコップと呼ぶ（率直に物事を呼ぶ）というラテン語起源のイディオム。", "examples": {"B": "遠回しに言わず、リックのプランはうまくいってないって伝えよう。", "C": "エムのフィードバックはありがたい。彼女は物事を率直に言ってくれるから。", "D": "率直にはっきり話す"}},
282: {"nativeDefinition": "To concentrate most of something at the beginning stage.", "japaneseMeaning": "（何かを）前倒しする、初期に集中させる", "etymology": "front（前）＋ load（積み込む）で、作業や負担を初期に偏らせる意。", "examples": {"B": "ジョンは昼のうちに米を用意して、夕食の調理を前倒しした。", "C": "プロジェクト初期にもっと人員を割り当てれば、仕事を前倒しできる？", "D": "初期段階に大部分を集中させる"}},
283: {"nativeDefinition": "To provide something gradually in small amounts over time.", "japaneseMeaning": "（何かを）少しずつ送る、段階的に提供する", "etymology": "点滴（drip feed）のように、少量ずつ時間をかけて供給する比喩。", "examples": {"B": "完成した書類から順に少しずつ送っていくね。", "C": "編集が終わった写真を、1日1枚ずつ少しずつ送るつもり。", "D": "徐々に少しずつ提供する"}},
284: {"nativeDefinition": "A pointless search or pursuit that wastes time and effort.", "japaneseMeaning": "無駄なあちこち探し、空振り", "etymology": "野生のガチョウを追う無意味な狩りから転じたイディオム。", "examples": {"B": "今朝はフリーWi-Fiを探してあちこち回っただけだった。", "C": "昼食のレストランを予約しておこう。食べる場所を探して空振りする羽目にならないように。", "D": "無意味な活動"}},
285: {"nativeDefinition": "To make something or someone look cleaner and more attractive.", "japaneseMeaning": "（何か・誰かを）きれいに整える、見た目をよくする", "etymology": "spruce（樅の木）から来た「smart に整える」という古い用法。", "examples": {"B": "送る前にプレゼンスライドをきれいに整える。", "C": "人を招く前に家を片付けて見た目をよくしよう。", "D": "見た目をすっきり魅力的にする"}},
286: {"nativeDefinition": "To try to understand something from someone else's perspective.", "japaneseMeaning": "（誰かの）立場で考える、身になってみる", "etymology": "相手の靴（shoes）を履いて歩く比喩で、他者の視点で考える意。", "examples": {"B": "顧客のニーズを理解するには、彼らの立場で考える必要がある。", "C": "サイモンが今何を感じているかわかるには、彼の立場で考えてみて。", "D": "誰かの視点から見る"}},
287: {"nativeDefinition": "To make effort but fail to make progress.", "japaneseMeaning": "空回りする、足踏みする", "etymology": "車のタイヤが空転（spin）して前に進まない比喩。", "examples": {"B": "明確な計画がないので、チームは先週から空回りしている。", "C": "リーダーシップがないままでは、私たちは足踏みしている。", "D": "努力しているのに進展がない"}},
288: {"nativeDefinition": "To speak condescendingly as if to someone inferior.", "japaneseMeaning": "（誰かに）見下した口調で話す、小ばかにする", "etymology": "上から目線で話す（talk down）ことで、相手を見下している態度を表す。", "examples": {"B": "セレナはいつも見下した口調で話してくる気がする。", "C": "ブライアンは見下した言い方で人を不快にさせる。", "D": "上から目線で話す"}},
289: {"nativeDefinition": "Arrogant and self-centered; thinking too highly of oneself.", "japaneseMeaning": "自己中心な、うぬぼれている", "etymology": "full of oneself（自分自身で満たされている）で、傲慢で自己陶酔した様子を表す。", "examples": {"B": "アキはかなりうぬぼれていて、他の人より自分は頑張らなくていいと思っている。", "C": "レオンはチームに不要だ。少し自己中なので、他のメンバーを不快にさせるかもしれない。", "D": "自己中心的"}},
290: {"nativeDefinition": "A brief overview or summary of complex information.", "japaneseMeaning": "概要、ひと目でわかる要約", "etymology": "snapshot（スナップ写真）のように、複雑な情報の一瞬の全体像を表す。", "examples": {"B": "複雑なデータの概要を示すには、パワポが向いている。", "C": "その図は日本の人口構成の全体像をよく示していた。", "D": "概要"}},
291: {"nativeDefinition": "Extremely difficult and frustrating, like extracting teeth.", "japaneseMeaning": "歯を抜くような、非常に難しい", "etymology": "歯を抜く（pull teeth）ほど骨の折れる苦労を表す比喩。", "examples": {"B": "銀行からわずか10ドル借りるのは歯を抜くみたいに大変だ。", "C": "グレッグを時間通りに出勤させるのは本当に骨が折れる。いつも遅刻するんだ。", "D": "非常に難しい"}},
292: {"nativeDefinition": "To make a final decision and act on it, especially a major purchase.", "japaneseMeaning": "決断して実行する、思い切って踏み切る", "etymology": "銃の引き金（trigger）を引く比喩で、迷いを断ち切って行動する意。", "examples": {"B": "値段は高かったが、リズは決心してボートを買った。", "C": "もう決断して家を買おう。", "D": "決断を下す"}},
293: {"nativeDefinition": "Suspicious, unreliable, or shady.", "japaneseMeaning": "怪しい、頼りない", "etymology": "sketch（下書き）から、未完成で粗っぽく信頼できないイメージ。", "examples": {"B": "怪しいセールスマン相手にうんざりだ。", "C": "ノートPCのカメラにテープを貼っている人を見るたび、すごく怪しいと思う。", "D": "疑わしい"}},
294: {"nativeDefinition": "An extremely wide variety of things; everything imaginable.", "japaneseMeaning": "ありとあらゆるもの、総て", "etymology": "太陽の下（under the sun）のすべてから、想像できる限りの物事を表す。", "examples": {"B": "スーパーでありとあらゆるものを買わないで。夕食は2人分だけだよ。", "C": "アーロンのスピーチは長すぎた。ありとあらゆることをカバーしようとしたから。", "D": "さまざまなもの"}},
295: {"nativeDefinition": "Permission or approval to proceed with something.", "japaneseMeaning": "許可、承認", "etymology": "go ahead（先に進め）で、進行の許可を表す名詞・表現。", "examples": {"B": "彼女が新しいポルシェを買っていいと許可してくれた。", "C": "マネージャーから許可が出次第、新製品の開発を始められる。", "D": "許可"}},
296: {"nativeDefinition": "To increase something significantly in scale or intensity.", "japaneseMeaning": "（何かを）大幅に増やす、強化する", "etymology": "ramp（勾配）を上げる（up）イメージで、量や規模を引き上げる。", "examples": {"B": "OPECが石油生産を増やせば通常価格は下がる。だが今回は予想外に値上がりした。", "C": "警察はNYCマラソンの警備を強化する予定だ。", "D": "何かを増やす"}},
297: {"nativeDefinition": "To improvise and decide as you go rather than planning ahead.", "japaneseMeaning": "臨機応変に対応する、状況を見ながら決める", "etymology": "楽譜なしに耳だけで演奏する（play by ear）から転じた。", "examples": {"B": "臨機応変に対応して、様子を見るしかない。", "C": "パーティーに何を持っていけばいいかわからない。まあ、そのとき考えよう。", "D": "即興で対応する"}},
298: {"nativeDefinition": "To make bad news or criticism seem nicer than it really is.", "japaneseMeaning": "（何かを）婉曲に言う、角を取って伝える", "etymology": "sugar（砂糖）＋ coat（コーティング）で、苦い内容を甘く包んで伝える比喩。", "examples": {"B": "ネガティブなフィードバックを婉曲に伝える方法はいくつかある。", "C": "悪い知らせは、角を取って伝えるより正直に伝えた方がいい。", "D": "より受け入れやすく見せる"}},
299: {"nativeDefinition": "An obsessive need for order, cleanliness, or perfection (often used casually).", "japaneseMeaning": "完璧主義、強迫的なこだわり", "etymology": "Obsessive-Compulsive Disorder（強迫性障害）の略。日常では細部への異常なこだわりを指すことも。", "examples": {"B": "レポート全体でフォントを統一しよう。クライアントは細部に異常にこだわる人だ。", "C": "強迫的なこだわりがあるので、エレベーターのボタンやエスカレーターの手すりには触れない。", "D": "几帳面、潔癖"}},
300: {"nativeDefinition": "Two things that seem different but are closely related aspects of the same thing.", "japaneseMeaning": "表裏一体、同じ物事の両面", "etymology": "同じコイン（coin）の表と裏（two sides）から、一見異なっても本質は同じことを表す。", "examples": {"B": "思いやりのある人であることと、良い聞き手であることは表裏一体だ。", "C": "成功と失敗は同じコインの両面だ。", "D": "同じ物事の二つの見方・解釈"}},
}
